import React, { useState, useEffect, useRef, useCallback } from "react";

const API = "http://localhost:8000";

const SUGGESTIONS = [
  "Which segment should I focus on first?",
  "Who are my most valuable customers?",
  "What are my top selling products?",
  "Which segment is most at risk of churning?",
  "What's my best sales day of the week?",
  "What % of revenue do my top segment drive?",
];

export default function AiChat({ context, compact = false }) {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [streaming, setStreaming] = useState(false);
  const bottomRef = useRef(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth", block: "nearest" });
  }, [messages]);

  const send = useCallback(async (text) => {
    const msg = (text || input).trim();
    if (!msg || streaming) return;
    setInput("");
    const userMsg = { role: "user", content: msg };
    setMessages(prev => [...prev, userMsg]);
    setStreaming(true);
    setMessages(prev => [...prev, { role: "assistant", content: "" }]);
    try {
      const res = await fetch(`${API}/ai/chat`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ message: msg, history: messages, context }),
      });
      if (!res.ok) throw new Error((await res.json().catch(() => ({}))).detail || "failed");
      const reader = res.body.getReader();
      const dec = new TextDecoder();
      let full = "";
      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        full += dec.decode(value, { stream: true });
        setMessages(prev => [...prev.slice(0, -1), { role: "assistant", content: full }]);
      }
    } catch (e) {
      setMessages(prev => [...prev.slice(0, -1), { role: "assistant", content: `⚠️ ${e.message}` }]);
    } finally {
      setStreaming(false);
    }
  }, [input, streaming, messages, context]);

  return (
    <div className={`ai-tool-card ai-chat-card ${compact ? "ai-chat-compact" : ""}`}>
      <div className="ai-tool-card-header">
        <div className="ai-tool-card-title">
          <span>🧠</span> Ask Your Data
          <span className="ai-chat-badge">AI</span>
        </div>
        {messages.length > 0 && (
          <button className="ai-chat-clear" onClick={() => setMessages([])}>Clear</button>
        )}
      </div>
      {messages.length === 0 && (
        <div className="ai-chat-suggestions">
          {SUGGESTIONS.map((s, i) => (
            <button key={i} className="suggestion-chip" onClick={() => send(s)}>{s}</button>
          ))}
        </div>
      )}
      <div className="ai-chat-messages">
        {messages.length === 0 ? (
          <div className="ai-chat-empty">
            <span className="ai-chat-empty-icon">💬</span>
            <p className="ai-chat-empty-text">Ask anything about your segments</p>
          </div>
        ) : messages.map((m, i) => (
          <div key={i} className={`chat-msg chat-msg-${m.role === "user" ? "user" : "ai"}`}>
            <div className="chat-msg-avatar">{m.role === "user" ? "👤" : "🧠"}</div>
            <div className="chat-msg-bubble">
              {m.role === "assistant" && m.content === "" ? (
                <div className="chat-typing">
                  <span className="chat-typing-dot" />
                  <span className="chat-typing-dot" />
                  <span className="chat-typing-dot" />
                </div>
              ) : m.content}
            </div>
          </div>
        ))}
        <div ref={bottomRef} />
      </div>
      <div className="ai-chat-input-row">
        <textarea
          className="ai-chat-input"
          placeholder="Ask a question about your data…"
          value={input}
          rows={1}
          onChange={e => setInput(e.target.value)}
          onKeyDown={e => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); send(); } }}
          disabled={streaming}
        />
        <button className="ai-chat-send" onClick={() => send()}
          disabled={!input.trim() || streaming}>↑</button>
      </div>
    </div>
  );
}
